  // Find the template dropdown trigger
  const templateDropdown = document.querySelector('.dropdown-toggle')?.closest('.dropdown');
  if (!templateDropdown) return { noDropdown: true };

  const templateLinks = templateDropdown.querySelectorAll('a');
  return Array.from(templateLinks).map(a => ({
    text: a.innerText?.trim()?.substring(0, 100),
    id: a.id,
    href: a.href,
    dataValue: a.getAttribute('data-value'),
