/**
 * TAPD 创建需求（Story）脚本
 * 工作区：31253609（月圆之夜）
 * 使用叶枝君的账号 cookies
 * 通过直接设置 hidden 字段值来避免 autocomplete 问题
 */

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const WS_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WS_DIR, 'tapd_cookies_yezhijun.json');
const WORKSPACE_ID = '31253609';
const STORY_CREATE_URL = `https://www.tapd.cn/${WORKSPACE_ID}/prong/stories/add`;

const STEALTH_SCRIPT = `
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
  Object.defineProperty(navigator, 'plugins', { get: () => [1, 2, 3, 4, 5] });
  Object.defineProperty(navigator, 'languages', { get: () => ['zh-CN', 'zh', 'en'] });
  Object.defineProperty(navigator, 'hardwareConcurrency', { get: () => 8 });
  window.chrome = { runtime: {} };
`;

/**
 * Create a Story (需求) on TAPD using 叶枝君's account
 */
export async function createStory(opts = {}) {
  const {
    title = '测试需求单 - 请忽略',
    priority = 'P2',
    module: mod = '1V1',
    version = '【1V1】正式版本V2.0',
    branch = 'YZY_1V1 V1.0 Beta',
    handler = '周以天',
    cc = '周以天',
    description = '',
  } = opts;

  if (!title) throw new Error('title is required');
  if (!fs.existsSync(COOKIES_FILE)) throw new Error(`Cookies file not found: ${COOKIES_FILE}`);

  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

  const browser = await chromium.launch({
    headless: false,
    args: [
      '--no-sandbox',
      '--disable-blink-features=AutomationControlled',
      '--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    ],
  });

  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  });

  await context.addInitScript(STEALTH_SCRIPT);
  await context.addCookies(cookies);

  const page = await context.newPage();

  try {
    console.log('1/9 Opening story create page...');
    await page.goto(STORY_CREATE_URL, { waitUntil: 'networkidle', timeout: 30000 });
    if (page.url().includes('login')) throw new Error('TAPD session expired, please re-login');
    await page.waitForTimeout(2000);

    // ===== 2. Select Template: 客户端 =====
    console.log('2/9 Selecting template: 客户端...');
    const templateToggle = page.locator('.dropdown-toggle').filter({ hasText: '系统默认模板1' }).first();
    await templateToggle.click();
    await page.waitForTimeout(1500);

    const templateClicked = await page.evaluate(() => {
      const items = document.querySelectorAll('.template-item');
      for (const item of items) {
        if (item.innerText.includes('客户端')) {
          const link = item.querySelector('a');
          if (link) { link.click(); return true; }
        }
      }
      return false;
    });

    console.log(templateClicked ? '  Client template selected ✓' : '  Default template used');
    await page.waitForTimeout(2000);

    // ===== 3. Title =====
    console.log('3/9 Filling title...');
    await page.fill('#StoryName', title);

    // ===== 4. Priority =====
    console.log('4/9 Setting priority P2...');
    await page.selectOption('#StoryPriority', priority);

    // ===== 5. Module =====
    console.log('5/9 Setting module: 1V1...');
    await page.selectOption('#StoryModule', { label: mod });

    // ===== 6. Version =====
    console.log('6/9 Setting version...');
    await page.selectOption('#StoryVersion', { label: version });

    // ===== 7. Set owner/handler and CC via JavaScript =====
    console.log('7/9 Setting autocomplete fields via JS...');
    await page.evaluate(({ handler, cc, branch }) => {
      // Set hidden fields directly
      const ownerHidden = document.getElementById('StoryOwner');
      if (ownerHidden) ownerHidden.value = handler;

      const ccHidden = document.getElementById('StoryCc');
      if (ccHidden) ccHidden.value = cc;

      const branchHidden = document.getElementById('StoryCustomFieldOne');
      if (branchHidden) branchHidden.value = branch;

      // Also set the visible fields for display
      const ownerVisible = document.getElementById('StoryOwnerValue');
      if (ownerVisible) ownerVisible.value = handler;

      const ccVisible = document.getElementById('StoryCcValue');
      if (ccVisible) ccVisible.value = cc;

      const branchVisible = document.getElementById('StoryCustomFieldOneValue');
      if (branchVisible) branchVisible.value = branch;

      // Trigger change events so TAPD knows the values were set
      [ownerHidden, ccHidden, branchHidden].forEach(el => {
        if (el) el.dispatchEvent(new Event('change', { bubbles: true }));
      });
    }, { handler, cc, branch });

    console.log(`  Handler: ${handler}`);
    console.log(`  CC: ${cc}`);
    console.log(`  Branch: ${branch}`);

    // ===== 8. Description =====
    if (description) {
      console.log('Setting description...');
      try {
        const descFrame = page.frameLocator('iframe#StoryDescription_ifr').first();
        await descFrame.locator('body').fill(description);
      } catch (e) {
        console.warn('Description field not found:', e.message);
      }
    }

    // ===== 9. Submit =====
    console.log('8/9 Submitting...');

    // Try click submit with navigation wait
    try {
      await Promise.all([
        page.waitForNavigation({ timeout: 30000 }),
        page.locator('#btn_save_view').click(),
      ]);
    } catch (e) {
      console.log('Navigation timeout, checking current state...');
      await page.waitForTimeout(3000);
    }

    const finalUrl = page.url();
    console.log('9/9 Final URL:', finalUrl);

    // Extract story ID
    const storyIdMatch = finalUrl.match(/stories\/(\d+)/) || finalUrl.match(/story\/(\d+)/) || finalUrl.match(/workitem_id=(\d+)/);
    const storyId = storyIdMatch ? storyIdMatch[1] : 'unknown';
    const detailUrl = `https://www.tapd.cn/31253609/prong/stories/view/${storyId}`;

    console.log(`\n✅ Story created: ${detailUrl}`);
    return { url: detailUrl, storyId };

  } finally {
    await browser.close();
  }
}

// CLI entry
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const args = process.argv.slice(2);
  const title = args[0] || '测试需求单 - 请忽略';
  createStory({ title })
    .then(result => {
      console.log('SUCCESS:', JSON.stringify(result));
      process.exit(0);
    })
    .catch(err => {
      console.error('FAILED:', err.message);
      process.exit(1);
    });
}

