function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

export async function createStory(opts = {}) {
  const {
    title = '测试需求单 - 请忽略',
    priority = 'P2',
    module: mod = '1V1',
    version = '【1V1】正式版本V2.0',
    handler = '周以天',
    description = '',
  } = opts;

  if (!title) throw new Error('title is required');
  if (!fs.existsSync(COOKIES_FILE)) throw new Error(`Cookies file not found: ${COOKIES_FILE}`);

  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

  const browser = await chromium.launch({
    headless: false,
    args: [
      '--no-sandbox',
      '--disable-blink-features=AutomationControlled',
      '--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    ],
  });

  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  });

  await context.addInitScript(STEALTH_SCRIPT);
  await context.addCookies(cookies);

  const page = await context.newPage();

  try {
    console.log('1/6 Opening story create page...');
    await page.goto(STORY_CREATE_URL, { waitUntil: 'networkidle', timeout: 30000 });
    if (page.url().includes('login')) throw new Error('TAPD session expired');
    await page.waitForTimeout(2000);

    // 2. Select template
    console.log('2/6 Selecting template: 客户端...');
    const templateToggle = page.locator('.dropdown-toggle').filter({ hasText: '系统默认模板1' }).first();
    await templateToggle.click();
    await page.waitForTimeout(1500);

    await page.evaluate(() => {
      const items = document.querySelectorAll('.template-item');
      for (const item of items) {
        if (item.innerText.includes('客户端')) {
          const link = item.querySelector('a');
          if (link) { link.click(); return; }
        }
      }
    });
    await page.waitForTimeout(2000);
    console.log('  Client template selected ✓');

    // 3. Fill basic fields (skip autocomplete fields)
    console.log('3/6 Filling basic fields...');
    await page.fill('#StoryName', title);
    await page.selectOption('#StoryPriority', priority);
    await page.selectOption('#StoryModule', { label: mod });
    await page.selectOption('#StoryVersion', { label: version });

    // Optional description
    if (description) {
      try {
        const descFrame = page.frameLocator('iframe#StoryDescription_ifr').first();
        await descFrame.locator('body').fill(description);
      } catch (e) {
        console.warn('Description field not found:', e.message);
      }
    }

    // 4. Submit
    console.log('4/6 Submitting...');
    await Promise.all([
      page.waitForNavigation({ timeout: 30000 }),
      page.locator('#btn_save_view').click(),
    ]);

    const finalUrl = page.url();
    console.log('  Navigated to:', finalUrl);

    // Extract story ID
    const storyIdMatch = finalUrl.match(/stories\/(\d+)/) || finalUrl.match(/story\/(\d+)/) || finalUrl.match(/workitem_id=(\d+)/);
    let storyId;
    let detailUrl;

    if (storyIdMatch) {
      storyId = storyIdMatch[1];
      detailUrl = `https://www.tapd.cn/${WORKSPACE_ID}/prong/stories/view/${storyId}`;
      console.log(`  Story ID: ${storyId}`);
    } else if (finalUrl.includes('story/detail/')) {
      storyId = finalUrl.split('story/detail/').pop();
      detailUrl = finalUrl;
      console.log(`  Story ID: ${storyId}`);
    } else {
      // Fallback - try navigating to list
      await page.goto(`https://www.tapd.cn/${WORKSPACE_ID}/prong/stories`, { waitUntil: 'networkidle', timeout: 15000 });
      await page.waitForTimeout(2000);

      // Find our story in the list
      const storyLink = page.locator('a').filter({ hasText: title }).first();
      const count = await storyLink.count();
      if (count > 0) {
        const href = await storyLink.getAttribute('href');
        detailUrl = href ? `https://www.tapd.cn${href}` : 'unknown';
        storyId = href?.split('/').pop() || 'unknown';
        console.log(`  Found story in list: ${detailUrl}`);
      } else {
        storyId = 'unknown';
        detailUrl = 'unknown';
        console.log('  Could not find story in list');
        return { url: detailUrl, storyId };
      }
    }

    // 5. Navigate to detail page to set handler
    console.log('5/6 Setting handler and CC on detail page...');
    await page.goto(detailUrl, { waitUntil: 'networkidle', timeout: 15000 });
    await page.waitForTimeout(2000);

    // Click edit to open edit mode
    // The detail page might have an "编辑" (edit) button
    const editBtn = page.locator('a, button').filter({ hasText: '编辑' }).first();
    const editCount = await editBtn.count();
    if (editCount > 0) {
      console.log('  Clicking edit button...');
      await editBtn.click();
      await page.waitForTimeout(2000);
    }

    // Try to find and set owner field on the edit page
    await page.evaluate(({ handler }) => {
      // Try to set owner
      const ownerHidden = document.getElementById('StoryOwner');
      if (ownerHidden) {
        ownerHidden.value = handler;
        ownerHidden.dispatchEvent(new Event('change', { bubbles: true }));
      }

      // Try visible field
      const ownerVisible = document.getElementById('StoryOwnerValue');
      if (ownerVisible) ownerVisible.value = handler;
    }, { handler });

    // Click save on the edit form if needed
    const saveBtn = page.locator('a, button').filter({ hasText: '保存' }).first();
    const saveCount = await saveBtn.count();
    if (saveCount > 0) {
      console.log('  Saving changes...');
      await saveBtn.click();
      await page.waitForTimeout(3000);
    }

    console.log(`\n✅ Story created: ${detailUrl}`);
    return { url: detailUrl, storyId };

  } finally {
    await browser.close();
  }
}

