export async function createStory(opts = {}) {
  const {
    title = '测试需求单 - 请忽略',
    priority = 'P2',
    module: mod = '1V1',
    version = '【1V1】正式版本V2.0',
    branch = 'YZY_1V1 V1.0 Beta',
    handler = '周以天',
    cc = '周以天',
    description = '',
  } = opts;

  if (!title) throw new Error('title is required');
  if (!fs.existsSync(COOKIES_FILE)) throw new Error(`Cookies file not found: ${COOKIES_FILE}`);

  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

  const browser = await chromium.launch({
    headless: false,
    args: [
      '--no-sandbox',
      '--disable-blink-features=AutomationControlled',
      '--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    ],
  });

  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  });

  await context.addInitScript(STEALTH_SCRIPT);
  await context.addCookies(cookies);

  const page = await context.newPage();

  try {
    console.log('1/7 Opening story create page...');
    await page.goto(STORY_CREATE_URL, { waitUntil: 'networkidle', timeout: 30000 });
    if (page.url().includes('login')) throw new Error('TAPD session expired');
    await page.waitForTimeout(2000);

    // 2. Select template: 客户端（这会触发页面 POST 刷新）
    console.log('2/7 Selecting template: 客户端...');
    const templateToggle = page.locator('.dropdown-toggle').filter({ hasText: '系统默认模板1' }).first();
    await templateToggle.click();
    await page.waitForTimeout(1500);

    await page.evaluate(() => {
      const items = document.querySelectorAll('.template-item');
      for (const item of items) {
        if (item.innerText.includes('客户端')) {
          const link = item.querySelector('a');
          if (link) { link.click(); return; }
        }
      }
    });

    // 等待模板选择后的页面刷新
    console.log('  Waiting for template page refresh...');
    await page.waitForNavigation({ timeout: 30000 });
    console.log('  Template selected, page refreshed:', page.url());
    await page.waitForTimeout(2000);

    // 3. Fill basic fields
    console.log('3/7 Filling fields...');
    await page.fill('#StoryName', title);
    await page.selectOption('#StoryPriority', priority);
    await page.selectOption('#StoryModule', { label: mod });
    await page.selectOption('#StoryVersion', { label: version });

    // 4. Set owner/CC via pinyinuserchooser
    console.log('4/7 Setting handler & CC...');

    // 处理人 - 周以天
    try {
      const ownerInput = page.locator('#StoryOwnerValue').first();
      await ownerInput.click();
      await ownerInput.type('周以天', { delay: 80 });
      await page.waitForTimeout(2000);
      // Try pressing down arrow to select the first dropdown item
      await page.keyboard.press('ArrowDown');
      await page.waitForTimeout(300);
      await page.keyboard.press('Enter');
      await page.waitForTimeout(500);
      console.log(`  Handler set: ${handler}`);
    } catch (e) {
      console.warn(`  Handler autocomplete failed: ${e.message}`);
      // Fallback: set hidden field directly
      await page.evaluate(({ handler }) => {
        const hidden = document.getElementById('StoryOwner');
        if (hidden) hidden.value = handler;
      }, { handler });
    }

    // 抄送
    try {
      const ccInput = page.locator('#StoryCcValue').first();
      await ccInput.click();
      await ccInput.type('周以天', { delay: 80 });
      await page.waitForTimeout(2000);
      await page.keyboard.press('ArrowDown');
      await page.waitForTimeout(300);
      await page.keyboard.press('Enter');
      await page.waitForTimeout(500);
      console.log(`  CC set: ${cc}`);
    } catch (e) {
      console.warn(`  CC autocomplete failed: ${e.message}`);
      await page.evaluate(({ cc }) => {
        const hidden = document.getElementById('StoryCc');
        if (hidden) hidden.value = cc;
      }, { cc });
    }

    // 研发分支
    try {
      const branchInput = page.locator('#StoryCustomFieldOneValue').first();
      await branchInput.click();
      await branchInput.type('YZY_1V1 V1.0 Beta', { delay: 50 });
      await page.waitForTimeout(2000);
      await page.keyboard.press('ArrowDown');
      await page.waitForTimeout(300);
      await page.keyboard.press('Enter');
      await page.waitForTimeout(500);
      console.log(`  Branch set: ${branch}`);
    } catch (e) {
      console.warn(`  Branch autocomplete failed: ${e.message}`);
      await page.evaluate(({ branch }) => {
        const hidden = document.getElementById('StoryCustomFieldOne');
        if (hidden) hidden.value = branch;
      }, { branch });
    }

    // 5. Description
    if (description) {
      console.log('Setting description...');
      try {
        const descFrame = page.frameLocator('iframe#StoryDescription_ifr').first();
        await descFrame.locator('body').fill(description);
      } catch (e) {
        console.warn('Description field not found:', e.message);
      }
    }

    // 6. Submit
    console.log('6/7 Submitting...');
    await Promise.all([
      page.waitForNavigation({ timeout: 30000 }),
      page.locator('#btn_save_view').click(),
    ]);

    const finalUrl = page.url();
    console.log('7/7 Navigated to:', finalUrl);

    // Extract story ID
    const storyIdMatch = finalUrl.match(/stories\/(\d+)/) || finalUrl.match(/story\/(\d+)/) || finalUrl.match(/story\/detail\/(\d+)/);
    let storyId, detailUrl;

    if (storyIdMatch) {
      storyId = storyIdMatch[1];
      detailUrl = `https://www.tapd.cn/${WORKSPACE_ID}/prong/stories/view/${storyId}`;
    } else {
      storyId = finalUrl;
      detailUrl = finalUrl;
    }

    console.log(`\n✅ Story created: ${detailUrl}`);
    return { url: detailUrl, storyId };

  } finally {
    await browser.close();
  }
}

// CLI entry
