page.on('request', req => {
  if (req.method() === 'POST' && req.url().includes('stories')) {
    console.log('POST:', req.url().substring(0, 200));
    console.log('  Data:', req.postData()?.substring(0, 500));
  }
});

// Directly open the page WITH workitem_type_id for 客户端 template
await page.goto('https://www.tapd.cn/31253609/prong/stories/add?workitem_type_id=1131253609001000033', { waitUntil: 'networkidle', timeout: 30000 });
if (page.url().includes('login')) { console.log('LOGIN_REDIRECT'); await browser.close(); process.exit(1); }
await page.waitForTimeout(3000);

// Check the page state - is the template already applied?
const templateCheck = await page.evaluate(() => {
  const formStory = document.getElementById('FormStory');
  if (!formStory) return { noFormStory: true, forms: Array.from(document.querySelectorAll('form')).map(f => f.id) };

  // Check if FormStory has the client template's preset items
  const presetInputs = formStory.querySelectorAll('[name*="PresetItems"]');
  const presetNames = Array.from(presetInputs)
    .filter(p => p.name.includes('[name]'))
    .map(p => p.value);

  const templateName = document.querySelector('.template-item.current')?.innerText?.trim()?.substring(0, 50) || 'unknown';

  // Check dsc_token / add_story_token
  const addToken = formStory.querySelector('[name="data[add_story_token]"]')?.value || 'no token';
  const dscTokens = formStory.querySelectorAll('input[name="dsc_token"]');

  return {
    templateName,
    presetNames,
    addStoryToken: addToken,
    dscTokenCount: dscTokens.length,
    hasSubmitBtn: !!document.getElementById('btn_save_view'),
  };
});
